-- Seed landing content into Strapi tables
-- Run: psql "postgresql://finance:finance@localhost:5432/finance_bot" -f apps/cms/src/seeds/seed.sql
--
-- В Strapi 5 с draftAndPublish:true каждый документ хранится ДВУМЯ строками
-- с одинаковым document_id: черновик (published_at IS NULL) и опубликованная (published_at IS NOT NULL).
-- UI редактирует черновик — поэтому нужны обе строки.

SET search_path = strapi, public;

-- Очистка
TRUNCATE faqs, pricings, home_pages, pages RESTART IDENTITY CASCADE;
DELETE FROM site_settings;

