DECLARE ss_id int;
BEGIN
  INSERT INTO site_settings(document_id,company_name,unp,email,phone,address,bot_username,telegram_support,created_at,updated_at)
  VALUES (gen_random_uuid()::text,'[BRAND_NAME]','[UNP]','[EMAIL]','[PHONE]','[ADDRESS]','valentinethebuhgalter_bot','[TELEGRAM_SUPPORT]',NOW(),NOW())
  RETURNING id INTO ss_id;

  -- Перепривязать логотип из media library к новой строке настроек (DELETE выше
  -- сбрасывает id). Если логотип ещё не загружали — UPDATE затронет 0 строк.
  UPDATE files_related_mph
  SET related_id = ss_id
  WHERE related_type = 'api::site-setting.site-setting' AND field = 'logo';
END $$;
